SELECT batch_id, harvest_year
FROM wine_batches
WHERE harvest_year = 2023;

SELECT COUNT(*) AS number_of_in_production_batches
FROM wine_batches
WHERE batch_status = 'in production';

SELECT COUNT(*) 
FROM wine_batches
WHERE vineyard_id = (SELECT vineyard_id FROM vineyards WHERE vineyard_name = 'Sample Vineyard');

SELECT vineyard_id, COUNT(batch_id) AS batch_count
FROM wine_batches
GROUP BY vineyard_id;
